#include <iostream>
#include <unordered_map>
#include <algorithm>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, K;
    cin >> N >> K;

    unordered_map<int, int> last_pos;
    int answer = -1;

    for (int pos = 0; pos < N; ++pos) {
        int id;
        cin >> id;

        auto it = last_pos.find(id);
        if (it != last_pos.end()) {
            if (pos - it->second <= K) {
                answer = max(answer, id);
            }
        }
        last_pos[id] = pos;
    }

    cout << answer << '\n';
    return 0;
}
